DO $$
begin

  create temp table &&existidToDelteTable&&(&&metadataId&& bigint, &&metadataHeaderId&& bigint);

  insert into &&existidToDelteTable&&(&&metadataId&&, &&metadataHeaderId&&) select &&Id&&, &&Header&& from &&MetadataItem&& where encode(&&Metadata&&, 'escape') like 'EleWise.ELMA.Model.Metadata.TablePartMetadata%';

  update &&MetadataItem&& set &&Header&& = null  where &&Id&& in (select &&metadataId&& from &&existidToDelteTable&&);

  delete from &&MetadataItemHeader&&  where &&Id&& in (select &&metadataHeaderId&& from &&existidToDelteTable&&);

  delete from &&MetadataItem&& where &&Id&& in (select &&metadataId&& from &&existidToDelteTable&&);

  drop table existidToDelteTable;

end
$$
language plpgsql;

procedure.text:

create or replace function CreateInstancePermission(tableName text, tablePermissionName text, sequenceName text, editProfilePermission uuid, 
viewProfilePermission uuid, fullPermission uuid, fullInstPermission uuid, editInstPerm uuid, viewInstPerm uuid, catalogUid uuid, groupRoleType uuid, recalculateAll int) 
returns void
as
$$
DECLARE
existIdSql text;
insertSQl text;
fullPermissionRecord record;
permissionRecord record;
begin
  create temp table existIdTable(catalogId bigint);
  if (recalculateAll = 1)
    then
      EXECUTE 'delete from ' || tablePermissionName || ' where &&Parent&& in (select &&Id&& from ' || tableName ||')';
  else
    EXECUTE 'insert into existIdTable(&&catalogId&&) select &&Parent&& from ' || tablePermissionName;
  end if;

  --fullAccessPermission
  for fullPermissionRecord in 
  select ussc.&&SetId&&, ussc.&&GroupId&&
  from &&UserSecuritySetCache&& ussc
  inner join &&GroupPermissions&& gp on ussc.&&GroupId&& = gp.&&GroupId&&
  where  &&PermissionId&& = fullPermission
  group by  ussc.&&SetId&&, ussc.&&GroupId&&
  loop
    begin
      insertSQl = 'insert into ' || tablePermissionName || ' (&&Id&&, &&UserSecuritySetCacheId&&, &&Parent&&, &&PermissionId&&, &&Group&&, &&PermissionRole&&, &&Uid&&) 
        select nextval(''' || sequenceName || '''), $1, Id, $2, $3, $4, uuid_generate_v4() from ' || tableName || '
         where not &&Id&& in (select &&catalogId&& from existIdTable)';
      execute insertSQl using fullPermissionRecord.&&SetId&&, fullInstPermission, fullPermissionRecord.&&GroupId&&, groupRoleType;
    end;
  end loop;

  --edit/view permission
  for permissionRecord in 
  select case ca.PermissionId
        when editProfilePermission then editInstPerm 
        when viewProfilePermission then viewInstPerm
      end &&PermissionId&&, &&UserSecuritySetCacheId&&, &&PermissionRole&&, &&User&&, &&OrganizationItemPosition&&, &&Group&&, &&OrganizationItem&&
    from &&CatalogAccess&& ca
    join &&CatalogProfile&& cp on cp.&&Id&& = ca.&&CatalogProfile&&
    where cp.&&CatalogType&& = catalogUid and &&PermissionId&& in (editProfilePermission, viewProfilePermission)
  loop
    begin

      insertSQl = 'insert into ' || tablePermissionName || '(&&Id&&, &&Parent&&, &&PermissionId&&, &&UserSecuritySetCacheid&&, &&PermissionRole&&, &&User&&, &&OrganizationItemPosition&&, &&Group&&, &&OrganizationItem&&, &&Uid&&) 
        select nextval(''' || sequenceName || '''), &&Id&&, $1, $2, $3, $4, $5, $6, $7, uuid_generate_v4()
        from ' || tableName || ' where not &&Id&& in (select &&catalogId&& from existIdTable)';
      execute insertSQl using permissionRecord.&&PermissionId&&, permissionRecord.&&UserSecuritySetCacheId&&, permissionRecord.&&PermissionRole&&,
        permissionRecord.&&User&&, permissionRecord.&&OrganizationItemPosition&&, permissionRecord.&&Group&&, permissionRecord.&&OrganizationItem&&;

      if permissionRecord.&&PermissionId&& = editInstPerm then
        execute insertSQl using viewInstPerm, permissionRecord.&&UserSecuritySetCacheId&&, permissionRecord.&&PermissionRole&&,
          permissionRecord.&&User&&, permissionRecord.&&OrganizationItemPosition&&, permissionRecord.&&Group&&, permissionRecord.&&OrganizationItem&&;
      end if;

    end;
  end loop;
drop table existIdTable;
end
$$
language plpgsql;


create or replace function CreateInstancePermissionInh(tableName text, tablePermissionName text, sequenceName text, editProfilePermission uuid, 
viewProfilePermission uuid, fullPermission uuid, fullInstPermission uuid, editInstPerm uuid, viewInstPerm uuid, catalogUid uuid, groupRoleType uuid, recalculateAll int, catalogTypeUid uuid) 
returns void
as
$$
DECLARE
existIdSql text;
insertSQl text;
fullPermissionRecord record;
permissionRecord record;
begin
  create temp table existIdTable(catalogId bigint);
  if (recalculateAll = 1)
    then
      EXECUTE 'delete from ' || tablePermissionName || ' where &&Parent&& in (select &&Id&& from ' || tableName ||')';
  else
    EXECUTE 'insert into existIdTable(&&catalogId&&) select &&Parent&& from ' || tablePermissionName;
  end if;

  --fullAccessPermission
  for fullPermissionRecord in 
  select ussc.&&SetId&&, ussc.&&GroupId&&
  from &&UserSecuritySetCache&& ussc
  inner join &&GroupPermissions&& gp on ussc.&&GroupId&& = gp.&&GroupId&&
  where  &&PermissionId&& = fullPermission
  group by  ussc.&&SetId&&, ussc.&&GroupId&&
  loop
    begin
      insertSQl = 'insert into ' || tablePermissionName || ' (&&Id&&, &&UserSecuritySetCacheId&&, &&Parent&&, &&PermissionId&&, &&Group&&, &&PermissionRole&&, &&Uid&&) 
        select nextval(''' || sequenceName || '''), $1, Id, $2, $3, $4, uuid_generate_v4() from ' || tableName || '
         where &&TypeUid&& = $5 and not &&Id&& in (select &&catalogId&& from existIdTable)';
      execute insertSQl using fullPermissionRecord.&&SetId&&, fullInstPermission, fullPermissionRecord.&&GroupId&&, groupRoleType, catalogTypeUid;
    end;
  end loop;

  --edit/view permission
  for permissionRecord in 
  select case ca.PermissionId
        when editProfilePermission then editInstPerm 
        when viewProfilePermission then viewInstPerm
      end &&PermissionId&&, &&UserSecuritySetCacheId&&, &&PermissionRole&&, &&User&&, &&OrganizationItemPosition&&, &&Group&& , &&OrganizationItem&&
    from &&CatalogAccess&& ca
    join &&CatalogProfile&& cp on cp.&&Id&& = ca.&&CatalogProfile&&
    where cp.&&CatalogType&& = catalogUid and &&PermissionId&& in (editProfilePermission, viewProfilePermission)
  loop
    begin
      insertSQl = 'insert into ' || tablePermissionName || '(&&Id&&, &&Parent&&, &&PermissionId&&, &&UserSecuritySetCacheid&&, &&PermissionRole&&, &&User&&, &&OrganizationItemPosition&&, &&Group&&, &&OrganizationItem&&, &&Uid&&) 
        select nextval(''' || sequenceName || '''), Id, $1, $2, $3, $4, $5, $6, $7, uuid_generate_v4()
        from ' || tableName || ' where &&TypeUid&& = $8 and not &&Id&& in (select &&catalogId&& from existIdTable)';
      execute insertSQl using permissionRecord.PermissionId, permissionRecord.&&UserSecuritySetCacheId&&, permissionRecord.&&PermissionRole&&,
        permissionRecord.&&User&&, permissionRecord.&&OrganizationItemPosition&&, permissionRecord.&&Group&&, permissionRecord.&&OrganizationItem&&, catalogTypeUid;
      if permissionRecord.&&PermissionId&& = editInstPerm then
        execute insertSQl using viewInstPerm, permissionRecord.&&UserSecuritySetCacheId&&, permissionRecord.&&PermissionRole&&,
          permissionRecord.&&User&&, permissionRecord.&&OrganizationItemPosition&&, permissionRecord.&&Group&&, permissionRecord.&&OrganizationItem&&, catalogTypeUid;
      end if;
    end;
  end loop;
drop table existIdTable;
end
$$
language plpgsql;
